// SPDX-License-Identifier: MIT
pragma solidity 0.8.28;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

//  SecureEthUsdcSwap — ETH <-> USDC Atomic Swap v9.0
//  Author: SecureSwap Team
//  Trustless peer-to-peer atomic swap between ETH and USDC with
//  symmetric MAD collateral, reputation scoring, and anti-griefing.
//  Final merged version: v8.0 architecture + v7.3 API refinements.
//
//  SECURITY FIXES:
//
//  [CRIT]  refund() counterparty access on FUNDED swaps.
//          Counterparty may call refund() once the reveal window closes
//          (revealDeadline + TIMESTAMP_DRIFT_BUFFER), not only after the
//          full swap deadline. Eliminates permanent USDC lock when initiator
//          disappears and closes the cross-chain timing exploit.
//
//  [CRIT]  Dead zone (~30 min) eliminated.
//          Previously: complete() closed at revealDeadline+15s, refund()
//          opened at deadline+15s. Fix: FUNDED refunds open at
//          revealDeadline+15s (adjacent windows).
//
//  [HIGH]  withdraw() split into withdrawEth() / withdrawUsdc().
//          USDC blacklisting no longer blocks ETH recovery.
//
//  [MED]   Bidirectional collusion detection via canonical pair key.
//
//  [LOW]   ETH burns are now real: _burnEth() does payable(0xdEaD).call{value}.
//
//  [LOW]   fund() checks collusion flag for designated counterparties too.
//
//  [LOW]   cancel() restricted to beforeDeadline + TIMESTAMP_DRIFT_BUFFER.
//
//  API REFINEMENTS (from v7.3):
//  - pendingEthWithdrawals: explicit naming over generic pendingWithdrawals
//  - error NotInitiatorOrCounterparty: more descriptive than NotParty
//  - event Refunded includes indexed caller address
//  - getPendingWithdrawals(address) view function added
//  - getPairGriefCount returns canonical order-independent count
//
//  INTENTIONAL DESIGN DECISIONS:
//  - usedSecretHashes is permanent (not cleared on cancel/refund).
//  - USDC burn is logical (tokens stay in contract).

// ════════════════════════════════════════════════════════════════
//  CUSTOM ERRORS
// ════════════════════════════════════════════════════════════════

error EmptyCommitment();
error AlreadyCommitted();
error NotYourCommitment();
error CommitmentUsed();
error CommitmentExpired();
error EthTooSmall();
error UsdcTooSmall();
error DurationTooShort();
error DurationTooLong();
error EmptySecretHash();
error EmptyNonce();
error SelfSwap();
error CollusionFlagActive();
error SecretHashReused();
error InitiateCooldownActive();
error TooManyActiveSwaps();
error WrongEthDeposit();
error BufferTooShort();
error IdCollision();
error WrongState();
error NotInitiator();
error NotCounterparty();
error NotInitiatorOrCounterparty();
error Expired();
error NotExpired();
error RevealWindowClosed();
error EmptySecret();
error WrongSecret();
error SelfFund();
error FundCooldownActive();
error CannotRefund();
error NothingToWithdraw();
error EthWithdrawFailed();
error EthBurnFailed();
error VolumeOverflow();
error InvalidAddress();
error UseInitiateFromCommit();

/// @title  SecureEthUsdcSwap — ETH <-> USDC Atomic Swap v9.0
/// @author SecureSwap Team
/// @notice Trustless peer-to-peer atomic swap between ETH and USDC with
///         symmetric MAD collateral, reputation scoring, and anti-griefing.
/// @dev    Final merged version: v8.0 architecture + v7.3 API refinements.
contract SecureEthUsdcSwap is ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ════════════════════════════════════════════════════════════════
    //  ENUMS
    // ════════════════════════════════════════════════════════════════

    /// @notice Actions tracked by the reputation system
    enum RepAction {
        COMPLETED,
        GRIEFED,
        VICTIMIZED,
        CANCELLED
    }

    /// @notice Swap lifecycle states
    enum State {
        EMPTY,
        INITIATED,
        FUNDED,
        COMPLETED,
        REFUNDED,
        CANCELLED
    }

    // ════════════════════════════════════════════════════════════════
    //  STRUCTS
    // ════════════════════════════════════════════════════════════════

    /// @notice On-chain reputation record for a user
    struct Reputation {
        uint64  completed;
        uint64  griefed;
        uint64  victimized;
        uint64  cancelled;
        uint128 volumeGwei;
    }

    /// @notice Full state of an atomic swap
    struct Swap {
        address payable initiator;
        address payable counterparty;
        uint256 ethAmount;
        uint256 usdcAmount;
        uint256 aCollateral;
        uint256 bCollateral;
        uint256 aPremium;
        uint256 createdAt;
        uint256 deadline;
        uint256 revealDeadline;
        bytes32 secretHash;
        bytes32 nonce;
        bytes32 secret;
        State   state;
    }

    /// @notice Commit-reveal commitment record
    struct Commitment {
        address initiator;
        uint256 createdAt;
        bool    used;
    }

    /// @notice Per-user rate limiting state
    struct RateLimit {
        uint256 lastInitiatedAt;
        uint256 lastFundedAt;
        uint32  activeCount;
    }

    // ════════════════════════════════════════════════════════════════
    //  CONSTANTS
    // ════════════════════════════════════════════════════════════════

    /// @notice USDC token contract (immutable, set in constructor)
    IERC20 public immutable USDC;

    uint256 private constant TIMESTAMP_DRIFT_BUFFER = 15 seconds;
    uint256 private constant MIN_DURATION           = 1 hours;
    uint256 private constant MAX_DURATION           = 7 days;
    uint256 private constant SECRET_REVEAL_BUFFER   = 30 minutes;
    uint256 private constant MIN_ETH                = 0.001 ether;
    uint256 private constant MIN_USDC               = 1e6;
    uint256 private constant COLLATERAL_BPS         = 500;
    uint256 private constant BPS_DENOMINATOR        = 10_000;
    uint256 private constant PREMIUM_BPS            = 200;
    uint256 private constant MIN_PREMIUM            = 0.0005 ether;
    uint256 private constant MAX_ACTIVE_PER_USER    = 5;
    uint256 private constant INITIATE_COOLDOWN      = 2 minutes;
    uint256 private constant COMMIT_EXPIRY          = 10 minutes;
    uint256 private constant FUND_COOLDOWN          = 1 minutes;
    uint32  private constant COLLUSION_THRESHOLD    = 2;
    uint256 private constant COLLUSION_FLAG_TIMEOUT = 30 days;

    /// @notice ETH physical burn target.
    /// @dev    Pure EOA on Ethereum mainnet — low-level call always succeeds.
    ///         Verify before deploying on L2s where this address may have code.
    address private constant BURN_ADDRESS = address(0xdEaD);

    // ════════════════════════════════════════════════════════════════
    //  STORAGE
    // ════════════════════════════════════════════════════════════════

    mapping(bytes32 swapId     => Swap)        public swaps;
    mapping(bytes32 commitHash => Commitment)  public commitments;
    mapping(address user       => Reputation)  public reputation;
    mapping(address user       => RateLimit)   public rateLimit;
    mapping(bytes32 hash       => bool used)   public usedSecretHashes;

    /// @notice Pending ETH withdrawal balances (pull-payment)
    mapping(address user => uint256 eth)  public pendingEthWithdrawals;
    /// @notice Pending USDC withdrawal balances (pull-payment)
    mapping(address user => uint256 usdc) public pendingUsdcWithdrawals;

    /// @notice Canonical-pair grief counter: key always (min(a,b) -> max(a,b)).
    /// @dev    A->B and B->A grief both increment the same slot.
    ///         Query via getPairGriefCount() for order-independent access.
    mapping(address lo => mapping(address hi => uint32 count))   public pairGriefCount;
    mapping(address a  => mapping(address b  => bool flagged))   public collusionFlag;
    mapping(address a  => mapping(address b  => uint256 expiry)) public collusionFlagExpiry;

    /// @notice USDC logically burned (remains in contract, permanently inaccessible)
    uint256 public burnedUsdcTotal;
    /// @notice ETH physically burned (sent to 0xdEaD, removed from balance)
    uint256 public burnedEthTotal;

    // ════════════════════════════════════════════════════════════════
    //  EVENTS
    // ════════════════════════════════════════════════════════════════

    event CommitmentMade(
        bytes32 indexed commitment,
        address indexed initiator,
        uint256 expiry
    );

    event Initiated(
        bytes32 indexed swapId,
        address indexed initiator,
        address indexed counterparty,
        uint256 ethAmount,
        uint256 usdcAmount,
        uint256 aCollateral,
        uint256 bCollateral,
        uint256 aPremium,
        uint256 deadline,
        uint256 revealDeadline,
        bytes32 nonce
    );

    event Funded(bytes32 indexed swapId, address indexed counterparty);

    event Completed(bytes32 indexed swapId, bytes32 secret);

    /// @notice Emitted when a swap is refunded.
    /// @param caller Address that triggered the refund (initiator or counterparty)
    event Refunded(bytes32 indexed swapId, bool griefed, address indexed caller);

    event Cancelled(bytes32 indexed swapId);

    event CollusionFlagged(address indexed a, address indexed b, uint256 expiry);

    event EthQueued(address indexed recipient, uint256 amount);
    event UsdcQueued(address indexed recipient, uint256 amount);
    event EthWithdrawn(address indexed recipient, uint256 amount);
    event UsdcWithdrawn(address indexed recipient, uint256 amount);

    /// @notice ETH physically sent to 0xdEaD
    event EthBurned(uint256 amount);
    /// @notice USDC logically burned (stays in contract)
    event UsdcBurned(uint256 amount);

    event ReputationUpdated(address indexed user, RepAction indexed action);

    // ════════════════════════════════════════════════════════════════
    //  CONSTRUCTOR
    // ════════════════════════════════════════════════════════════════

    /// @param _usdc Address of the USDC ERC-20 contract
    constructor(address _usdc) payable {
        if (_usdc == address(0)) revert InvalidAddress();
        USDC = IERC20(_usdc);
    }

    // ════════════════════════════════════════════════════════════════
    //  MODIFIERS
    // ════════════════════════════════════════════════════════════════

    /// @dev Requires swap to be in a specific state
    modifier onlyState(bytes32 id, State s) {
        if (swaps[id].state != s) revert WrongState();
        _;
    }

    /// @dev block.timestamp must be strictly before deadline + TIMESTAMP_DRIFT_BUFFER
    modifier beforeDeadline(bytes32 id) {
        if (block.timestamp >= swaps[id].deadline + TIMESTAMP_DRIFT_BUFFER) revert Expired();
        _;
    }

    // ════════════════════════════════════════════════════════════════
    //  PURE HELPERS
    // ════════════════════════════════════════════════════════════════

    /// @notice Calculate ETH collateral (5%)
    function calcCollateralEth(uint256 ethAmount) public pure returns (uint256) {
        return (ethAmount * COLLATERAL_BPS) / BPS_DENOMINATOR;
    }

    /// @notice Calculate USDC collateral (5%)
    function calcCollateralUsdc(uint256 usdcAmount) public pure returns (uint256) {
        return (usdcAmount * COLLATERAL_BPS) / BPS_DENOMINATOR;
    }

    /// @notice Calculate premium: max(ethAmount x 2%, MIN_PREMIUM)
    function calcPremium(uint256 ethAmount) public pure returns (uint256) {
        uint256 p = (ethAmount * PREMIUM_BPS) / BPS_DENOMINATOR;
        return p < MIN_PREMIUM ? MIN_PREMIUM : p;
    }

    /// @notice Total ETH initiator must deposit
    function requiredEthDeposit(uint256 ethAmount) public pure returns (uint256) {
        return ethAmount + calcCollateralEth(ethAmount) + calcPremium(ethAmount);
    }

    /// @notice Total USDC counterparty must deposit
    function requiredUsdcDeposit(uint256 usdcAmount) public pure returns (uint256) {
        return usdcAmount + calcCollateralUsdc(usdcAmount);
    }

    /// @dev Normalise address pair to (lo, hi) where lo < hi.
    ///      Ensures pairGriefCount is indexed consistently regardless of order.
    function _canonicalPair(address a, address b)
        internal pure returns (address lo, address hi)
    {
        (lo, hi) = a < b ? (a, b) : (b, a);
    }

    // ════════════════════════════════════════════════════════════════
    //  COLLUSION DETECTION
    // ════════════════════════════════════════════════════════════════

    /// @dev Returns true if the active collusion flag exists between a and b
    function _isCollusionActive(address a, address b) internal view returns (bool) {
        if (!collusionFlag[a][b]) return false;
        return block.timestamp < collusionFlagExpiry[a][b];
    }

    /// @dev Set or refresh collusion flag (both directions) with 30-day expiry
    function _flagCollusion(address a, address b) internal {
        if (!collusionFlag[a][b] || block.timestamp >= collusionFlagExpiry[a][b]) {
            collusionFlag[a][b] = true;
            collusionFlag[b][a] = true;
            uint256 expiry = block.timestamp + COLLUSION_FLAG_TIMEOUT;
            collusionFlagExpiry[a][b] = expiry;
            collusionFlagExpiry[b][a] = expiry;
            emit CollusionFlagged(a, b, expiry);
        }
    }

    // ════════════════════════════════════════════════════════════════
    //  REPUTATION SYSTEM
    // ════════════════════════════════════════════════════════════════

    /// @dev Record successful swap; increment completed count and volume for both parties
    function _repCompleted(
        address initiator,
        address counterparty,
        uint256 ethAmount
    ) internal {
        Reputation storage repA = reputation[initiator];
        Reputation storage repB = reputation[counterparty];

        repA.completed++;
        repB.completed++;

        uint128 volumeToAdd = uint128(ethAmount / 1 gwei);

        uint128 newVolA = repA.volumeGwei + volumeToAdd;
        if (newVolA < repA.volumeGwei) revert VolumeOverflow();
        repA.volumeGwei = newVolA;

        uint128 newVolB = repB.volumeGwei + volumeToAdd;
        if (newVolB < repB.volumeGwei) revert VolumeOverflow();
        repB.volumeGwei = newVolB;

        emit ReputationUpdated(initiator,    RepAction.COMPLETED);
        emit ReputationUpdated(counterparty, RepAction.COMPLETED);
    }

    /// @dev Record griefing (initiator failed to reveal secret in time).
    function _repGriefed(address initiator, address counterparty) internal {
        Reputation storage repA = reputation[initiator];
        Reputation storage repB = reputation[counterparty];

        repA.griefed++;
        repB.victimized++;

        (address lo, address hi) = _canonicalPair(initiator, counterparty);
        pairGriefCount[lo][hi]++;

        if (pairGriefCount[lo][hi] >= COLLUSION_THRESHOLD) {
            _flagCollusion(initiator, counterparty);
        }

        emit ReputationUpdated(initiator,    RepAction.GRIEFED);
        emit ReputationUpdated(counterparty, RepAction.VICTIMIZED);
    }

    /// @dev Record swap cancellation (reputation penalty for initiator)
    function _repCancelled(address initiator) internal {
        reputation[initiator].cancelled++;
        emit ReputationUpdated(initiator, RepAction.CANCELLED);
    }

    // ════════════════════════════════════════════════════════════════
    //  PULL-PAYMENT INTERNALS
    // ════════════════════════════════════════════════════════════════

    /// @dev Queue ETH for pull-payment withdrawal
    function _queueEth(address recipient, uint256 amount) internal {
        if (amount != 0 && recipient != address(0)) {
            pendingEthWithdrawals[recipient] += amount;
            emit EthQueued(recipient, amount);
        }
    }

    /// @dev Queue USDC for pull-payment withdrawal
    function _queueUsdc(address recipient, uint256 amount) internal {
        if (amount != 0 && recipient != address(0)) {
            pendingUsdcWithdrawals[recipient] += amount;
            emit UsdcQueued(recipient, amount);
        }
    }

    /// @dev Logically burn USDC: increment counter, tokens remain in contract.
    function _burnUsdc(uint256 amount) internal {
        if (amount != 0) {
            burnedUsdcTotal += amount;
            emit UsdcBurned(amount);
        }
    }

    /// @dev Physically burn ETH via low-level call to 0xdEaD.
    function _burnEth(uint256 amount) internal {
        if (amount != 0) {
            burnedEthTotal += amount;
            emit EthBurned(amount);
            (bool ok,) = payable(BURN_ADDRESS).call{value: amount}("");
            if (!ok) revert EthBurnFailed();
        }
    }

    /// @dev Safely decrement active swap count (guards against underflow)
    function _decrementActive(address user) internal {
        if (rateLimit[user].activeCount != 0) {
            rateLimit[user].activeCount--;
        }
    }

    // ════════════════════════════════════════════════════════════════
    //  STEP 0 — COMMIT (MEV protection)
    // ════════════════════════════════════════════════════════════════

    /// @notice Submit a commitment hash before initiating a swap.
    /// @dev    Prevents front-running: parameters hidden until reveal step.
    /// @param  commitment keccak256(abi.encode(secretHash, nonce, counterparty,
    ///                    ethAmount, usdcAmount, duration, msg.sender, salt))
    function commitInitiate(bytes32 commitment) external {
        if (commitment == bytes32(0)) revert EmptyCommitment();
        if (commitments[commitment].initiator != address(0)) revert AlreadyCommitted();

        commitments[commitment] = Commitment({
            initiator: msg.sender,
            createdAt: block.timestamp,
            used:      false
        });

        emit CommitmentMade(commitment, msg.sender, block.timestamp + COMMIT_EXPIRY);
    }

    // ════════════════════════════════════════════════════════════════
    //  STEP 1 — INITIATE
    // ════════════════════════════════════════════════════════════════

    /// @notice Create a swap by revealing a previously submitted commitment.
    /// @param  commitment   Commitment hash from commitInitiate()
    /// @param  salt         Random salt used when building the commitment
    /// @param  secretHash   keccak256(abi.encode(secret, nonce))
    /// @param  nonce        Additional entropy bound into secretHash
    /// @param  counterparty Designated counterparty; address(0) = open swap
    /// @param  ethAmount    ETH to swap (wei)
    /// @param  usdcAmount   USDC expected in return (atomic units)
    /// @param  duration     Swap lifetime in seconds
    /// @return swapId       Unique identifier for the created swap
    function initiateFromCommit(
        bytes32 commitment,
        bytes32 salt,
        bytes32 secretHash,
        bytes32 nonce,
        address counterparty,
        uint256 ethAmount,
        uint256 usdcAmount,
        uint256 duration
    )
        external
        payable
        nonReentrant
        returns (bytes32 swapId)
    {
        {
            bytes32 expected = keccak256(abi.encode(
                secretHash, nonce, counterparty,
                ethAmount, usdcAmount, duration,
                msg.sender, salt
            ));
            if (expected != commitment) revert EmptyCommitment();
        }

        Commitment storage c = commitments[commitment];
        if (c.initiator != msg.sender)                      revert NotYourCommitment();
        if (c.used)                                          revert CommitmentUsed();
        if (block.timestamp > c.createdAt + COMMIT_EXPIRY)  revert CommitmentExpired();
        c.used = true;

        if (ethAmount   < MIN_ETH)      revert EthTooSmall();
        if (usdcAmount  < MIN_USDC)     revert UsdcTooSmall();
        if (duration    < MIN_DURATION) revert DurationTooShort();
        if (duration    > MAX_DURATION) revert DurationTooLong();
        if (secretHash == bytes32(0))   revert EmptySecretHash();
        if (nonce      == bytes32(0))   revert EmptyNonce();
        if (counterparty == msg.sender) revert SelfSwap();

        if (counterparty != address(0)) {
            if (_isCollusionActive(msg.sender, counterparty)) revert CollusionFlagActive();
        }

        if (usedSecretHashes[secretHash]) revert SecretHashReused();
        usedSecretHashes[secretHash] = true;

        RateLimit storage rl = rateLimit[msg.sender];
        if (block.timestamp < rl.lastInitiatedAt + INITIATE_COOLDOWN) revert InitiateCooldownActive();
        if (rl.activeCount >= MAX_ACTIVE_PER_USER)                      revert TooManyActiveSwaps();
        rl.lastInitiatedAt = block.timestamp;
        rl.activeCount++;

        uint256 aCollateral = calcCollateralEth(ethAmount);
        uint256 bCollateral = calcCollateralUsdc(usdcAmount);
        uint256 aPremium    = calcPremium(ethAmount);
        if (msg.value != ethAmount + aCollateral + aPremium) revert WrongEthDeposit();

        uint256 deadline       = block.timestamp + duration;
        uint256 revealDeadline = deadline - SECRET_REVEAL_BUFFER;
        if (revealDeadline <= block.timestamp) revert BufferTooShort();

        swapId = keccak256(abi.encodePacked(commitment, block.chainid));
        if (swaps[swapId].state != State.EMPTY) revert IdCollision();

        swaps[swapId] = Swap({
            initiator:      payable(msg.sender),
            counterparty:   payable(counterparty),
            ethAmount:      ethAmount,
            usdcAmount:     usdcAmount,
            aCollateral:    aCollateral,
            bCollateral:    bCollateral,
            aPremium:       aPremium,
            createdAt:      block.timestamp,
            deadline:       deadline,
            revealDeadline: revealDeadline,
            secretHash:     secretHash,
            nonce:          nonce,
            secret:         bytes32(0),
            state:          State.INITIATED
        });

        emit Initiated(
            swapId, msg.sender, counterparty,
            ethAmount, usdcAmount,
            aCollateral, bCollateral, aPremium,
            deadline, revealDeadline, nonce
        );
    }

    // ════════════════════════════════════════════════════════════════
    //  STEP 2 — FUND
    // ════════════════════════════════════════════════════════════════

    /// @notice Fund a swap as counterparty by depositing USDC + collateral.
    /// @param  swapId The swap to fund
    function fund(bytes32 swapId)
        external
        nonReentrant
        onlyState(swapId, State.INITIATED)
        beforeDeadline(swapId)
    {
        Swap storage s = swaps[swapId];

        if (block.timestamp > s.revealDeadline) revert RevealWindowClosed();

        if (s.counterparty != address(0)) {
            if (msg.sender != s.counterparty) revert NotCounterparty();
            if (_isCollusionActive(msg.sender, s.initiator)) revert CollusionFlagActive();
        } else {
            if (msg.sender == s.initiator) revert SelfFund();
            if (_isCollusionActive(msg.sender, s.initiator)) revert CollusionFlagActive();
            s.counterparty = payable(msg.sender);
        }

        RateLimit storage rl = rateLimit[msg.sender];
        if (block.timestamp < rl.lastFundedAt + FUND_COOLDOWN) revert FundCooldownActive();
        if (rl.activeCount >= MAX_ACTIVE_PER_USER)               revert TooManyActiveSwaps();
        rl.lastFundedAt = block.timestamp;
        rl.activeCount++;

        s.state = State.FUNDED;

        USDC.safeTransferFrom(msg.sender, address(this), s.usdcAmount + s.bCollateral);

        emit Funded(swapId, msg.sender);
    }

    // ════════════════════════════════════════════════════════════════
    //  STEP 3 — COMPLETE
    // ════════════════════════════════════════════════════════════════

    /// @dev Shared completion logic.
    function _executeCompletion(bytes32 swapId, bytes32 secret) internal {
        Swap storage s = swaps[swapId];

        if (s.state != State.FUNDED) revert WrongState();
        if (block.timestamp > s.revealDeadline + TIMESTAMP_DRIFT_BUFFER) revert RevealWindowClosed();
        if (secret == bytes32(0)) revert EmptySecret();
        if (keccak256(abi.encode(secret, s.nonce)) != s.secretHash) revert WrongSecret();

        s.secret = secret;
        s.state  = State.COMPLETED;

        address initiator    = s.initiator;
        address counterparty = s.counterparty;

        _decrementActive(initiator);
        _decrementActive(counterparty);
        _repCompleted(initiator, counterparty, s.ethAmount);

        _queueEth(initiator,    s.aCollateral + s.aPremium);
        _queueEth(counterparty, s.ethAmount);
        _queueUsdc(initiator,    s.usdcAmount);
        _queueUsdc(counterparty, s.bCollateral);

        emit Completed(swapId, secret);
    }

    /// @notice Complete the swap by revealing the secret (initiator path).
    function complete(bytes32 swapId, bytes32 secret) external nonReentrant {
        if (msg.sender != swaps[swapId].initiator) revert NotInitiator();
        _executeCompletion(swapId, secret);
    }

    /// @notice Complete the swap by revealing the secret (counterparty path).
    function claimAsCounterparty(bytes32 swapId, bytes32 secret) external nonReentrant {
        if (msg.sender != swaps[swapId].counterparty) revert NotCounterparty();
        _executeCompletion(swapId, secret);
    }

    // ════════════════════════════════════════════════════════════════
    //  REFUND
    // ════════════════════════════════════════════════════════════════

    /// @notice Refund a swap after its effective expiry.
    /// @param  swapId Swap identifier
    function refund(bytes32 swapId) external nonReentrant {
        Swap storage s = swaps[swapId];

        if (s.state != State.INITIATED && s.state != State.FUNDED) {
            revert CannotRefund();
        }

        bool griefed = (s.state == State.FUNDED);

        if (griefed) {
            if (block.timestamp <= s.revealDeadline + TIMESTAMP_DRIFT_BUFFER) {
                revert NotExpired();
            }
            if (msg.sender != s.initiator && msg.sender != s.counterparty) {
                revert NotInitiatorOrCounterparty();
            }
        } else {
            if (block.timestamp < s.deadline + TIMESTAMP_DRIFT_BUFFER) {
                revert NotExpired();
            }
            if (msg.sender != s.initiator) {
                revert NotInitiator();
            }
        }

        s.state = State.REFUNDED;

        address initiator    = s.initiator;
        address counterparty = s.counterparty;

        _decrementActive(initiator);

        if (griefed) {
            _decrementActive(counterparty);
