        return block.timestamp <=
            swaps[swapId].revealDeadline + TIMESTAMP_DRIFT_BUFFER;
    }

    /// @notice Check if a user can initiate a new swap right now
    function canInitiate(address user)
        external view returns (bool ok, string memory reason)
    {
        RateLimit storage rl = rateLimit[user];
        if (rl.activeCount >= MAX_ACTIVE_PER_USER)
            return (false, "Too many active swaps");
        if (block.timestamp < rl.lastInitiatedAt + INITIATE_COOLDOWN)
