    function getPendingWithdrawals(address user)
        external view returns (uint256 pendingEth, uint256 pendingUsdc)
    {
        pendingEth  = pendingEthWithdrawals[user];
        pendingUsdc = pendingUsdcWithdrawals[user];
    }

